import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CurrentSpeed {
  download: number;
  upload: number;
  ping: number;
}

interface SpeedTrend {
  download: number[];
  upload: number[];
  ping: number[];
}

interface NetworkSpeedData {
  currentSpeed: CurrentSpeed;
  speedTrend: SpeedTrend;
}

export default function Widget() {
  const networkSpeedData = response.data as NetworkSpeedData;
  const { currentSpeed, speedTrend } = networkSpeedData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#121212' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="#0D47A1">
              Network Speed Monitor
            </Typography>
            <Stack direction="row" spacing={3} sx={{ mt: 1 }}>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Download
                </Typography>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#FF5722' }}>
                  {currentSpeed.download} Mbps
                </Typography>
              </Box>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Upload
                </Typography>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#FF5722' }}>
                  {currentSpeed.upload} Mbps
                </Typography>
              </Box>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Ping
                </Typography>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#FF5722' }}>
                  {currentSpeed.ping} ms
                </Typography>
              </Box>
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: speedTrend.download,
                  color: '#0D47A1',
                  label: 'Download',
                  curve: 'linear',
                },
                {
                  type: 'line',
                  data: speedTrend.upload,
                  color: '#FF5722',
                  label: 'Upload',
                  curve: 'linear',
                },
                {
                  type: 'line',
                  data: speedTrend.ping,
                  color: '#4CAF50',
                  label: 'Ping',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  data: speedTrend.download.map((_, index) => index),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'speed' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="speed"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
